describe("streamChat (redesign) — existing SSE behavior unchanged", () => {
  it("calls onText for each text event", async () => {
    const stream = makeStream([
      sseEvent("text", { content: "Hello" }),
      sseEvent("text", { content: " world" }),
      sseEvent("done", {}),
    ]);
    mockFetch.mockResolvedValueOnce({ ok: true, body: stream });

    const onText = vi.fn();
    await streamChat(makeRequest(), makeCallbacks({ onText }));

    expect(onText).toHaveBeenCalledTimes(2);
    expect(onText).toHaveBeenNthCalledWith(1, "Hello");
    expect(onText).toHaveBeenNthCalledWith(2, " world");
  });

  it("calls onError for 'error' SSE event", async () => {
    const stream = makeStream([
      sseEvent("error", { message: "Tool execution failed" }),
    ]);
    mockFetch.mockResolvedValueOnce({ ok: true, body: stream });

    const onError = vi.fn();
    await streamChat(makeRequest(), makeCallbacks({ onError }));

    expect(onError).toHaveBeenCalledWith("Tool execution failed");
  });

  it("calls onError for HTTP non-ok responses", async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 503,
      statusText: "Service Unavailable",
    });

    const onError = vi.fn();
    await streamChat(makeRequest(), makeCallbacks({ onError }));

    expect(onError).toHaveBeenCalledOnce();
    expect(onError.mock.calls[0][0]).toMatch(/503/);
  });

  it("resolves silently when already aborted before fetch", async () => {
    const controller = new AbortController();
    controller.abort();

    const onError = vi.fn();
    await streamChat(
      makeRequest(),
      makeCallbacks({ onError }),
      controller.signal,
    );

    expect(onError).not.toHaveBeenCalled();
    expect(mockFetch).not.toHaveBeenCalled();
  });
});
